
/* Swipers */

// interview
const interviewSwiper = new Swiper(".interview__swiper", {
    slidesPerView: 1.1,
    spaceBetween: 12,
    pagination: {
        el: ".interview__swiper-pagination",
    },
    breakpoints: {
        1200: {
            slidesPerView: 3,
            spaceBetween: 30,
        },
        700: {
            slidesPerView: 2.1,
            spaceBetween: 20,
        },
    },
});

const comfortSwiper = new Swiper(".comfort__swiper", {
    slidesPerView: "auto",
    spaceBetween: 12,
    navigation: {
        nextEl: ".comfort__swiper-button-next",
        prevEl: ".comfort__swiper-button-prev",
    },
    pagination: {
        el: ".comfort__swiper-pagination",
    },
    breakpoints: {
        768: {
            pagination: {
                el: ".comfort__swiper-pagination",
                type: "fraction",
            },
        },
    },
});

// services
if(window.innerWidth < 1200) {
    const servicesSwiper = new Swiper(".services__swiper", {
        slidesPerView: 1.1,
        spaceBetween: 12,
        pagination: {
            el: ".services__swiper-pagination",
        },
        breakpoints: {
            700: {
                slidesPerView: 2.1,
                spaceBetween: 20,
            },
        },
    });
}

